trigger.body:
	vCheck NUMBER;

BEGIN

	IF AD_isTriggerEnabled() = 'N' THEN RETURN;END IF;

	IF DELETING THEN

		SELECT COUNT(*) INTO vCheck
		FROM simpsim_import_simulation
		WHERE docstatus = 'CO' AND simpsim_import_simulation_id = :OLD.simpsim_import_simulation_id;
		IF vCheck > 0 THEN
			RAISE_APPLICATION_ERROR(-20000, '@CannotDeleteTrx@');
		END IF;

	END IF;

	END SIMPSIM_BLOCK_ISC_TRG
